const post = $json.body;

const system = `You write LinkedIn posts for Kadyn, a young investor who runs Kadyn's Fireplace, a finance education site built around one idea: the lack of equity in America sets entire families back for decades, and people his age keep sitting out of markets while the gap compounds.

Voice: direct, personal, a little fed up with how many people his age ignore investing. Plain English — no corporate tone, no buzzwords, no emoji spam, no hashtag walls (2-3 niche hashtags max, at the very end). The post should read like a person talking, not a brand.`;

const user = `Write a LinkedIn post promoting my new blog article.

Title: ${post.title}
Excerpt: ${post.excerpt || '(none)'}
Article URL: ${post.url}

Full article content (markdown):
${post.content}

Requirements:
- Open with a scroll-stopping first line. LinkedIn truncates after ~2 lines, so the hook matters most.
- Share one genuinely useful piece or insight FROM the article — give real value, don't just tease.
- End with a line inviting people to read the full article, followed by the URL on its own line.
- 900-1300 characters total. Short paragraphs with line breaks between them.
- Return ONLY the post text, nothing else — no preamble, no quotes around it.`;

return [{
  json: {
    claudeRequest: {
      model: 'claude-opus-4-8',
      max_tokens: 4000,
      thinking: { type: 'adaptive' },
      system,
      messages: [{ role: 'user', content: user }],
    },
  },
}];

// The Messages API returns a content array that may include thinking blocks;
// only the text blocks are the actual post.
const blocks = $json.content || [];
const text = blocks
  .filter((b) => b.type === 'text')
  .map((b) => b.text)
  .join('\n')
  .trim();

if (!text) {
  throw new Error('Claude returned no text — check the Draft with Claude node output.');
}

const post = $('Blog Published Webhook').first().json.body;

return [{
  json: {
    linkedinPost: text,
    title: post.title,
    url: post.url,
    slug: post.slug,
  },
}];
